namespace sv_666e6e7b639246dba5427005f7d9b685.Services;

public class WarehouseState
{
    public static readonly (string Id, string Name)[] Warehouses =
    [
        ("WH-001", "Warehouse A — Downtown"),
        ("WH-002", "Warehouse B — Airport"),
        ("WH-003", "Warehouse C — Harbor"),
    ];

    public string CurrentWarehouseId { get; private set; } = Warehouses[0].Id;

    public string CurrentWarehouseName =>
        Array.Find(Warehouses, w => w.Id == CurrentWarehouseId).Name ?? CurrentWarehouseId;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (warehouseId == CurrentWarehouseId) return;
        CurrentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_666e6e7b639246dba5427005f7d9b685.Services;

public class InventoryAlertService
{
    private readonly Random _random = new();

    /// <summary>
    /// Simulates a database query that returns the number of items
    /// below minimum stock levels for the given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        int count = _random.Next(0, 16);
        return Task.FromResult(count);
    }
}

namespace sv_666e6e7b639246dba5427005f7d9b685.Services;

/// <summary>
/// Scoped (per-circuit) state that holds the latest low-stock alert count
/// so that both the sidebar badge and the dashboard page stay in sync.
/// </summary>
public class AlertState
{
    public int LowStockCount { get; private set; }

    public event Action? OnChange;

    public void Update(int count)
    {
        LowStockCount = count;
        OnChange?.Invoke();
    }
}

