@page "/dashboard"
@rendermode InteractiveServer
@implements IDisposable

@using sv_666e6e7b639246dba5427005f7d9b685.Services

@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@inject AlertState AlertState

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text text-muted">
            Site ID: <code>@WarehouseState.CurrentWarehouseId</code>
        </p>
    </div>
</div>

<div class="row g-4">
    <div class="col-md-4">
        <div class="card text-bg-@(AlertState.LowStockCount > 0 ? "danger" : "success")">
            <div class="card-body text-center">
                <h2 class="display-4">@AlertState.LowStockCount</h2>
                <p class="card-text">Low-Stock Alerts</p>
                <small class="opacity-75">
                    @if (_lastChecked is not null)
                    {
                        <text>Last checked: @_lastChecked.Value.ToString("HH:mm:ss")</text>
                    }
                    else
                    {
                        <text>Checking…</text>
                    }
                </small>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card text-bg-info">
            <div class="card-body text-center">
                <h2 class="display-4">—</h2>
                <p class="card-text">Pending Shipments</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card text-bg-warning">
            <div class="card-body text-center">
                <h2 class="display-4">—</h2>
                <p class="card-text">Open Orders</p>
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private DateTime? _lastChecked;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await StartPollingAsync();
        }
    }

    private async void OnWarehouseChanged()
    {
        // Restart polling for the newly selected warehouse.
        await StopPollingAsync();
        await InvokeAsync(async () =>
        {
            await StartPollingAsync();
            StateHasChanged();
        });
    }

    private async Task StartPollingAsync()
    {
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        // Initial fetch, then poll every 10 seconds.
        while (!token.IsCancellationRequested)
        {
            try
            {
                var count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
                _lastChecked = DateTime.Now;
                AlertState.Update(count);

                await InvokeAsync(StateHasChanged);
                await Task.Delay(TimeSpan.FromSeconds(10), token);
            }
            catch (TaskCanceledException)
            {
                break;
            }
        }
    }

    private async Task StopPollingAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

